static const char *get_content_type(const char *path) {
    const char *ext = strrchr(path, '.');
    if (!ext) return "application/octet-stream";
    if (strcmp(ext, ".html") == 0) return "text/html";
    if (strcmp(ext, ".css") == 0) return "text/css";
    if (strcmp(ext, ".js") == 0) return "application/javascript";
    return "application/octet-stream";
}

static int hexval(char c) {
    if (c >= '0' && c <= '9') return c - '0';
    if (c >= 'a' && c <= 'f') return 10 + (c - 'a');
    if (c >= 'A' && c <= 'F') return 10 + (c - 'A');
    return -1;
}

// Decode %XX in URL paths. Keeps other bytes as-is.
// Returns 0 on success, -1 on error/overflow.
static int url_percent_decode(const char *in, char *out, size_t out_sz) {
    size_t oi = 0;
    for (size_t i = 0; in[i] != '\0'; i++) {
        if (oi + 1 >= out_sz) return -1;
        if (in[i] == '%' && in[i+1] && in[i+2]) {
            int hi = hexval(in[i+1]);
            int lo = hexval(in[i+2]);
            if (hi < 0 || lo < 0) return -1;
            out[oi++] = (char)((hi << 4) | lo);
            i += 2;
        } else {
            out[oi++] = in[i];
        }
    }
    out[oi] = '\0';
    return 0;
}

static int decoded_path_has_dotdot_segment(const char *path) {
    const char *p = path;
    while (*p) {
        while (*p == '/') p++;
        if (!*p) break;
        const char *seg = p;
        while (*p && *p != '/') p++;
        size_t len = (size_t)(p - seg);
        if (len == 2 && seg[0] == '.' && seg[1] == '.') return 1;
    }
    return 0;
}

static enum MHD_Result serve_static_file(struct MHD_Connection *connection,
                                        const char *url) {
    // Forbid any traversal attempts (including percent-encoded dot-dot)
    char decoded[512];
    if (url_percent_decode(url, decoded, sizeof(decoded)) != 0) {
        struct MHD_Response *r = MHD_create_response_from_buffer(
            9, (void *)"Forbidden", MHD_RESPMEM_PERSISTENT);
        enum MHD_Result ret = MHD_queue_response(connection, MHD_HTTP_FORBIDDEN, r);
        MHD_destroy_response(r);
        return ret;
    }
    if (decoded_path_has_dotdot_segment(decoded)) {
        struct MHD_Response *r = MHD_create_response_from_buffer(
            9, (void *)"Forbidden", MHD_RESPMEM_PERSISTENT);
        enum MHD_Result ret = MHD_queue_response(connection, MHD_HTTP_FORBIDDEN, r);
        MHD_destroy_response(r);
        return ret;
    }

    char filepath[512];
    const char *path = (strcmp(url, "/") == 0) ? "/index.html" : url;
    snprintf(filepath, sizeof(filepath), "%s%s", WWW_DIR, path);

    struct stat st;
    if (stat(filepath, &st) != 0) return MHD_NO;

    FILE *f = fopen(filepath, "rb");
    if (!f) return MHD_NO;

    char *buf = malloc(st.st_size);
    if (!buf) {
        fclose(f);
        return MHD_NO;
    }
    fread(buf, 1, st.st_size, f);
    fclose(f);

    struct MHD_Response *response = MHD_create_response_from_buffer(
        st.st_size, buf, MHD_RESPMEM_MUST_FREE);
    MHD_add_response_header(response, "Content-Type", get_content_type(filepath));
    enum MHD_Result ret = MHD_queue_response(connection, MHD_HTTP_OK, response);
    MHD_destroy_response(response);
    return ret;
}

static void request_completed(void *cls, struct MHD_Connection *connection,
                              void **con_cls, enum MHD_RequestTerminationCode toe) {
    (void)cls;
    (void)connection;
    (void)toe;
    if (con_cls && *con_cls) {
        struct connection_info *ci = *con_cls;
        if (ci->data) free(ci->data);
        free(ci);
        *con_cls = NULL;
    }
}

static enum MHD_Result handle_request(void *cls,
                                     struct MHD_Connection *connection,
                                     const char *url, const char *method,
                                     const char *version,
                                     const char *upload_data,
                                     size_t *upload_data_size,
                                     void **con_cls) {
    (void)cls;
    (void)version;

    if (strncmp(url, "/api/", 5) == 0) {
        return route_request(connection, url, method, upload_data,
                             upload_data_size, con_cls);
    }

    if (strcmp(method, "GET") == 0) {
        enum MHD_Result ret = serve_static_file(connection, url);
        if (ret == MHD_YES) return ret;
    }

    struct MHD_Response *response = MHD_create_response_from_buffer(
        9, (void *)"Not Found", MHD_RESPMEM_PERSISTENT);
    enum MHD_Result ret = MHD_queue_response(connection, MHD_HTTP_NOT_FOUND, response);
    MHD_destroy_response(response);
    return ret;
}

int main(void) {
    signal(SIGINT, handle_signal);
    signal(SIGTERM, handle_signal);

    mkdir("/app/data", 0755);

    if (init_db("/app/data/notes.db") != 0) {
